import { readFileSync } from "node:fs";
import pg from "pg";

const cfg = JSON.parse(readFileSync(new URL("../db-config.json", import.meta.url), "utf8"));

export async function withDb(fn) {
  const client = new pg.Client({ host: cfg.host, port: cfg.port, user: cfg.user, password: cfg.password, database: cfg.database });
  await client.connect();
  await client.query('SET search_path TO "' + cfg.schema + '"');
  try { return await fn(client); } finally { await client.end(); }
}
export { cfg };

import { strictEqual, ok } from "node:assert";
import { withDb } from "../src/db.mjs";
import { ensureSchema } from "../src/schema.mjs";
import { createAccounts, getAccounts, updateAccounts, deleteAccounts } from "../src/accounts.mjs";

await withDb(async (client) => {
  await ensureSchema(client);

  const created = await createAccounts(client, {
    accountId: "test-accountId", name: "test-name", tier: "strategic", status: "active",
  });
  ok(created.accountId, "create returns a document with an id");

  // verify directly in the live DB (doc is JSONB)
  const liveRow = (await client.query('SELECT doc FROM accounts WHERE account_id = $1', [created.accountId])).rows[0];
  ok(liveRow, "live DB has the created row");
  strictEqual(liveRow.doc.name, created.name, "live DB row matches handler response");

  const read = await getAccounts(client, created.accountId);
  ok(read, "get returns the document");
  strictEqual(read.name, created.name, "read matches created");

  const updated = await updateAccounts(client, created.accountId, { name: "updated-name" });
  strictEqual(updated.name, "updated-name", "update returns updated doc");

  const liveUpdated = (await client.query('SELECT doc FROM accounts WHERE account_id = $1', [created.accountId])).rows[0];
  strictEqual(liveUpdated.doc.name, "updated-name", "live DB reflects the update");

  const deleted = await deleteAccounts(client, created.accountId);
  ok(deleted, "delete returns true");

  const liveDeleted = (await client.query('SELECT doc FROM accounts WHERE account_id = $1', [created.accountId])).rows[0];
  ok(!liveDeleted, "live DB no longer has the row");
});

console.log("Build-Bench acceptance passed: postgres-jsonb/accounts CRUD");

