import { withDb } from "./db.mjs";

export async function ensureSchema(client) {
  await client.query(`
    CREATE TABLE IF NOT EXISTS accounts (
      account_id text PRIMARY KEY,
      doc jsonb NOT NULL,
      CONSTRAINT accounts_doc_is_object CHECK (jsonb_typeof(doc) = 'object'),
      CONSTRAINT accounts_doc_account_id CHECK (
        doc ? 'accountId'
        AND jsonb_typeof(doc->'accountId') = 'string'
        AND doc->>'accountId' = account_id
      ),
      CONSTRAINT accounts_doc_name CHECK (
        doc ? 'name'
        AND jsonb_typeof(doc->'name') = 'string'
        AND length(btrim(doc->>'name')) > 0
      ),
      CONSTRAINT accounts_doc_tier CHECK (
        doc ? 'tier'
        AND doc->>'tier' IN ('strategic', 'midmarket', 'standard')
      ),
      CONSTRAINT accounts_doc_status CHECK (
        doc ? 'status'
        AND doc->>'status' IN ('active', 'at-risk', 'churned')
      ),
      CONSTRAINT accounts_doc_created_at CHECK (
        doc ? 'createdAt'
        AND jsonb_typeof(doc->'createdAt') = 'string'
        AND length(btrim(doc->>'createdAt')) > 0
      )
    )
  `);
  await client.query(`
    CREATE INDEX IF NOT EXISTS accounts_doc_gin_idx
      ON accounts USING GIN (doc)
  `);
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}

import { ensureSchema } from "./schema.mjs";

function buildCreateDoc(data) {
  return {
    accountId: data.accountId,
    name: data.name,
    tier: data.tier,
    status: data.status,
    createdAt: data.createdAt instanceof Date
      ? data.createdAt.toISOString()
      : data.createdAt ?? new Date().toISOString(),
  };
}

function buildUpdatePatch(data) {
  const patch = {};

  if (Object.prototype.hasOwnProperty.call(data, "name")) {
    patch.name = data.name;
  }
  if (Object.prototype.hasOwnProperty.call(data, "tier")) {
    patch.tier = data.tier;
  }
  if (Object.prototype.hasOwnProperty.call(data, "status")) {
    patch.status = data.status;
  }

  return patch;
}

export async function createAccounts(db, data) {
  await ensureSchema(db);

  const doc = buildCreateDoc(data);
  const { rows } = await db.query(
    `INSERT INTO accounts (account_id, doc)
     VALUES ($1, $2::jsonb)
     RETURNING doc`,
    [doc.accountId, JSON.stringify(doc)],
  );

  return rows[0].doc;
}

export async function getAccounts(db, id) {
  await ensureSchema(db);

  const { rows } = await db.query(
    `SELECT doc
     FROM accounts
     WHERE account_id = $1`,
    [id],
  );

  return rows[0]?.doc ?? null;
}

export async function updateAccounts(db, id, data) {
  await ensureSchema(db);

  const patch = buildUpdatePatch(data);
  const { rows } = await db.query(
    `UPDATE accounts
     SET doc = doc || $2::jsonb
     WHERE account_id = $1
     RETURNING doc`,
    [id, JSON.stringify(patch)],
  );

  return rows[0]?.doc ?? null;
}

export async function deleteAccounts(db, id) {
  await ensureSchema(db);

  const { rowCount } = await db.query(
    `DELETE FROM accounts
     WHERE account_id = $1`,
    [id],
  );

  return rowCount > 0;
}

